      status.status = RotationStatus.WARNING;
      report.warning.push(status);
    } else {
      status.status = RotationStatus.OK;
      report.ok.push(status);
    }
  }

  return report;
}

function formatTable(secrets: SecretStatus[]): string {
  if (secrets.length === 0) return "";

  const headers = [
