    const config = {
      secrets: [
        {
          name: "test-secret",
          lastRotated: "2026-04-26",
          rotationPolicyDays: 30,
          requiredBy: ["service"],
        },
      ],
      warningWindowDays: 7,
      outputFormat: "json",
      referenceDate: "2026-05-06",
    };

